const d = $input.first().json;
const category = (d.category || '').toLowerCase();
const isFoodOrSupp = category.includes('food') || category.includes('beverage') || category.includes('supplement') || category.includes('wellness');
const isElectronics = category.includes('electronic');

// Category-aware line items with default monthly amounts
let advItems, promoItems, nwItems;

if (isFoodOrSupp) {
  advItems = [
    { desc: 'In-Store Sampling Materials', monthly: 500 },
    { desc: 'Influencer / Food Blogger Partnerships', monthly: 2000 },
    { desc: 'Product Photography & Video', monthly: 1500 },
    { desc: 'Press Kits & Mailers', monthly: 300 },
    { desc: 'Sam\'s Club Co-Op Signage', monthly: 0 },
  ];
  promoItems = [
    { desc: 'Sam\'s Club Roadshow Promo', monthly: 0 },
    { desc: 'Digital Coupons / Instant Savings', monthly: 0 },
    { desc: 'Google (PMAX, Search, YouTube)', monthly: 0 },
    { desc: 'Meta (Facebook/Instagram)', monthly: 0 },
    { desc: 'Instacart / Retailer Media', monthly: 0 },
    { desc: 'UGC / Affiliate', monthly: 1000 },
  ];
  nwItems = [
    { desc: 'Shopify / E-Commerce Platform', monthly: 500 },
    { desc: 'Email Marketing (Klaviyo/Mailchimp)', monthly: 400 },
    { desc: 'Food Safety Compliance Costs', monthly: 200 },
    { desc: 'Analytics & Reporting Tools', monthly: 150 },
  ];
} else {
  advItems = [
    { desc: 'Press Kits & Mailers', monthly: 300 },
    { desc: 'Influencer Partnerships', monthly: 3000 },
    { desc: 'Product Samples / Demos', monthly: 0 },
    { desc: 'Product Photography & Video', monthly: 1000 },
    { desc: 'Sam\'s Club Co-Op Signage', monthly: 0 },
  ];
  promoItems = [
    { desc: 'UGC / Affiliate', monthly: 1000 },
    { desc: 'Google (PMAX, Search, YouTube)', monthly: 0 },
    { desc: 'Meta (Facebook/Instagram)', monthly: 0 },
    { desc: 'Advertorial (news/feature ads)', monthly: 0 },
    { desc: 'Retailer Media Buys', monthly: 0 },
    { desc: 'Instacart', monthly: 0 },
  ];
  nwItems = [
    { desc: 'Shopify / E-Commerce Platform', monthly: 500 },
    { desc: 'Email Marketing (Klaviyo/Mailchimp)', monthly: 1200 },
    { desc: 'Analytics & Reporting Tools', monthly: 0 },
  ];
}

// Build rows for Google Sheets append
const months = ['JAN','FEB','MAR','APR','MAY','JUN','JUL','AUG','SEP','OCT','NOV','DEC'];
const rows = [];

// Header row
rows.push({ Section: 'A&P MARKETING BUDGET TRACKER', Description: `${d.brandName} - Sam\'s Club Roadshow 2026`, Category: d.category || '' });
rows.push({ Section: '', Description: `Prepared by Ascenda Group | Revenue: ${d.revenue || 'TBD'}` });
rows.push({ Section: '' });

// Advertising section
rows.push({ Section: 'ADVERTISING', Description: 'Awareness / Brand Building (55% allocation)', Allocation: '55%' });
rows.push({ Section: 'Line Item', Description: 'Description', JAN: 'JAN', FEB: 'FEB', MAR: 'MAR', APR: 'APR', MAY: 'MAY', JUN: 'JUN', JUL: 'JUL', AUG: 'AUG', SEP: 'SEP', OCT: 'OCT', NOV: 'NOV', DEC: 'DEC', TOTAL: 'TOTAL' });
advItems.forEach(item => {
  const row = { Description: item.desc };
  months.forEach(m => row[m] = item.monthly);
  row.TOTAL = item.monthly * 12;
  rows.push(row);
});
rows.push({ Description: 'ADVERTISING SUBTOTAL', TOTAL: advItems.reduce((s, i) => s + i.monthly * 12, 0) });
rows.push({ Section: '' });

// Promotional section
rows.push({ Section: 'PROMOTIONAL', Description: 'Conversion / Performance (17% allocation)', Allocation: '17%' });
rows.push({ Section: 'Line Item', Description: 'Description', JAN: 'JAN', FEB: 'FEB', MAR: 'MAR', APR: 'APR', MAY: 'MAY', JUN: 'JUN', JUL: 'JUL', AUG: 'AUG', SEP: 'SEP', OCT: 'OCT', NOV: 'NOV', DEC: 'DEC', TOTAL: 'TOTAL' });
promoItems.forEach(item => {
  const row = { Description: item.desc };
  months.forEach(m => row[m] = item.monthly);
  row.TOTAL = item.monthly * 12;
  rows.push(row);
});
rows.push({ Description: 'PROMOTIONAL SUBTOTAL', TOTAL: promoItems.reduce((s, i) => s + i.monthly * 12, 0) });
rows.push({ Section: '' });

// Non-Working section
rows.push({ Section: 'NON WORKING', Description: 'Subscriptions / Platforms / Consulting (28% allocation)', Allocation: '28%' });
rows.push({ Section: 'Line Item', Description: 'Description', JAN: 'JAN', FEB: 'FEB', MAR: 'MAR', APR: 'APR', MAY: 'MAY', JUN: 'JUN', JUL: 'JUL', AUG: 'AUG', SEP: 'SEP', OCT: 'OCT', NOV: 'NOV', DEC: 'DEC', TOTAL: 'TOTAL' });
nwItems.forEach(item => {
  const row = { Description: item.desc };
  months.forEach(m => row[m] = item.monthly);
  row.TOTAL = item.monthly * 12;
  rows.push(row);
});
rows.push({ Description: 'NON WORKING SUBTOTAL', TOTAL: nwItems.reduce((s, i) => s + i.monthly * 12, 0) });
rows.push({ Section: '' });

const grandTotal = [...advItems, ...promoItems, ...nwItems].reduce((s, i) => s + i.monthly * 12, 0);
rows.push({ Description: 'GRAND TOTAL A&P BUDGET', TOTAL: grandTotal });

return rows.map(r => ({ json: r }));
